class StockSpanner {
    Stack<Integer> prices;
    Stack<Integer> spans;

    public StockSpanner() {
        prices = new Stack<>();
        spans = new Stack<>();
    }

    public int next(int price) {
        int span = 1;
        while (!prices.isEmpty() && prices.peek() <= price) {
            span += spans.pop();
            prices.pop();
        }
        spans.push(span);
        prices.push(price);
        return span;
    }
}
```
